package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class LineItemTest {

  private Object lineItem;
  private Class<?> lineItemClass;

  @BeforeEach
  void setUp() throws Exception {
    lineItemClass = Class.forName("com.google.gson.examples.android.model.LineItem");
    lineItem = lineItemClass.getConstructor(String.class, int.class, long.class, String.class)
        .newInstance("TestName", 5, 1000L, "USD");
  }

  @Test
  void testGetName() throws Exception {
    var getNameMethod = lineItemClass.getMethod("getName");
    String name = (String) getNameMethod.invoke(lineItem);
    assertEquals("TestName", name);
  }
}
